  constructor(
    @Inject('MESSAGING_OPTIONS') private options: MessagingOptions,
  ) {}

  async sendEmail(to: string, subject: string, body: string) {
    console.log(`Envoi email via Mailgun avec clé: ${this.options.mailgunApiKey}`);
